#include <stdio.h>

struct Employee {
    int id;
    char name[20];
    float base_salary;
};

int main() {
    struct Employee emp = {101, "John", 5000.0};
    float net_salary = emp.base_salary * 1.10;
    printf("Employee: %s, Net Salary: %.2f\n", emp.name, net_salary);
    return 0;
}
